import { Component,OnInit } from '@angular/core';
import { DonorService } from '../../Services/DonorService';
import { Donor } from '../../Services/DonorService';
import { Observable } from 'rxjs';
import { DonorModel } from '../../Models/Donor';
import { TableModule } from 'primeng/table';
import { BrowserAnimationsModule } from '@angular/platform-browser/animations';


@Component({
  selector: 'app-donors-comp',
    standalone: true,  // ✅ זה חייב להיות Standalone

  imports: [TableModule, BrowserAnimationsModule,    CommonModule
],
  templateUrl: './donors-comp.html',
  styleUrls: ['./donors-comp.scss'],
})
export class DonorsComp implements OnInit {

  donors: Donor[] = [];
  loading: boolean = true;
  constructor(private donorService: DonorService) { }


    ngOnInit() {
      alert("Welcome to the Donors Page!");
    this.donorService.getAllDonors().subscribe({
      next: (res) => {
        this.donors = res;
        this.loading = false;
      },
      error: (err) => {
        console.error(err);
        this.loading = false;
      }
    });

}
}
